"""Public-API surface tests for ``load_full_chain`` (Step 12c.bis).

These tests lock the public name + signature the generated REST notebook
depends on. A future rename or dropped-kwarg would break the notebook
on the cluster silently; this test catches that regression.
"""

from __future__ import annotations

import inspect
import pathlib

import pytest


def test_load_full_chain_importable_from_orchestrator():
    """The notebook generated by build_notebook imports load_full_chain
    via this exact path. Any rename breaks the cluster runtime."""
    from oracle_ai_data_platform_fusion_bundle.orchestrator.content_pack import (
        load_full_chain,
    )
    assert callable(load_full_chain)


def test_make_filesystem_base_resolver_importable_from_orchestrator():
    from oracle_ai_data_platform_fusion_bundle.orchestrator.content_pack import (
        make_filesystem_base_resolver,
    )
    assert callable(make_filesystem_base_resolver)


def test_load_full_chain_signature_has_base_resolver_kwarg():
    """Phase 2 added ``base_resolver`` as a kwarg. Removing it would
    break overlay packs cluster-side (which need the staged resolver)
    and CLI-side (which need the filesystem resolver).
    """
    from oracle_ai_data_platform_fusion_bundle.orchestrator.content_pack import (
        load_full_chain,
    )
    sig = inspect.signature(load_full_chain)
    assert "base_resolver" in sig.parameters
    # Must be keyword-only (defensive against future positional-arg additions).
    param = sig.parameters["base_resolver"]
    assert param.kind == inspect.Parameter.KEYWORD_ONLY


def test_load_full_chain_works_on_non_overlay_pack(tmp_path: pathlib.Path):
    """Backward compatibility: a base pack (no extends) loads cleanly
    with the default filesystem resolver."""
    from oracle_ai_data_platform_fusion_bundle.orchestrator.content_pack import (
        load_full_chain,
    )
    pack_root = tmp_path / "p"
    pack_root.mkdir()
    (pack_root / "pack.yaml").write_text("""
id: simple
version: 1.0.0
compatibility:
  pluginMinVersion: 0.3.0
""")
    result = load_full_chain(pack_root)
    assert result.pack.id == "simple"


def test_cli_backward_compat_alias_still_works(tmp_path: pathlib.Path):
    """commands.content_pack._load_full_chain (Phase 1 callsite) still
    works post-promotion via the backward-compat alias."""
    from oracle_ai_data_platform_fusion_bundle.commands.content_pack import (
        _load_full_chain,
    )
    pack_root = tmp_path / "p"
    pack_root.mkdir()
    (pack_root / "pack.yaml").write_text("""
id: simple
version: 1.0.0
compatibility:
  pluginMinVersion: 0.3.0
""")
    result = _load_full_chain(pack_root)
    assert result.pack.id == "simple"
